import{c as a,Q as r,j as t,m as i}from"./chunks/framework.DVkeSyfh.js";const p=JSON.parse('{"title":"Smart Set Builder routing","description":"","frontmatter":{},"headers":[],"relativePath":"ru/concepts/smart-set-builder-routing.md","filePath":"ru/concepts/smart-set-builder-routing.md","lastUpdated":null}'),s={name:"ru/concepts/smart-set-builder-routing.md"};function o(d,e,n,l,c,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="smart-set-builder-routing" tabindex="-1">Smart Set Builder routing <a class="header-anchor" href="#smart-set-builder-routing" aria-label="Permalink to &quot;Smart Set Builder routing&quot;">​</a></h1><p>Аудитория: пользователи, которым нужно понять SET output<br> Цель: объяснить seeds, anchors, BPM, diversity и guards<br> Тип: explanation</p><p>Smart Set Builder генерирует ordered previews. Это route planner поверх local analysis data, а не автоматический final set.</p><h2 id="candidate-requirements" tabindex="-1">Candidate requirements <a class="header-anchor" href="#candidate-requirements" aria-label="Permalink to &quot;Candidate requirements&quot;">​</a></h2><p>SET requires candidates with:</p><ul><li>SONARA features;</li><li>MERT embeddings;</li><li>MAEST embeddings;</li><li>CLAP audio embeddings.</li></ul><p>Tracks без любого required input не feature-complete для SET.</p><h2 id="manual-seeds" tabindex="-1">Manual seeds <a class="header-anchor" href="#manual-seeds" aria-label="Permalink to &quot;Manual seeds&quot;">​</a></h2><p>Manual mode использует от одного до пяти selected seed tracks. Known artists должны быть unique среди seeds.</p><h2 id="auto-anchors" tabindex="-1">Auto anchors <a class="header-anchor" href="#auto-anchors" aria-label="Permalink to &quot;Auto anchors&quot;">​</a></h2><p>Auto mode samples first anchor из full feature-complete library, затем samples remaining waypoint anchors из related candidates. Generated route bridges between anchors.</p><h2 id="diversity-and-energy" tabindex="-1">Diversity and energy <a class="header-anchor" href="#diversity-and-energy" aria-label="Permalink to &quot;Diversity and energy&quot;">​</a></h2><p><code>Diversity</code> меняет, насколько широко route исследует related candidates. <code>Energy curve</code> формирует route как warmup, balanced, peak или wave.</p><h2 id="bpm-modes" tabindex="-1">BPM modes <a class="header-anchor" href="#bpm-modes" aria-label="Permalink to &quot;BPM modes&quot;">​</a></h2><p><code>general</code> сохраняет normal transition compatibility. <code>low_to_high</code> and <code>high_to_low</code> добавляют actual-BPM trajectory с <code>slow</code>, <code>medium</code> или <code>fast</code> change. Missing start/target BPM can be inferred from first seed/anchor and library range.</p><p>Half/double tempo matching помогает compatibility. Оно не меняет actual BPM trajectory.</p><h2 id="classifier-modifiers" tabindex="-1">Classifier modifiers <a class="header-anchor" href="#classifier-modifiers" aria-label="Permalink to &quot;Classifier modifiers&quot;">​</a></h2><p>Promoted classifiers - optional score modifiers. Missing scores neutral. Classifier flow может быть flat, rise или fall across preview.</p><h2 id="artist-guard" tabindex="-1">Artist guard <a class="header-anchor" href="#artist-guard" aria-label="Permalink to &quot;Artist guard&quot;">​</a></h2><p>Generated preview keeps at most one track per known artist. Unknown artists guarded reliably быть не могут, поэтому clean metadata все еще важна.</p>',20)])])}const h=a(s,[["render",o]]);export{p as __pageData,h as default};
